architect_plan:
{
  "summary": "Implement global keyboard listeners for Ctrl+C and Ctrl+V to handle object duplication with a spatial offset in the DocumentContext.",
  "plan": [
    {
      "step": 1,
      "title": "Analyze existing clipboard state and actions",
      "description": "Examine `client/src/lib/editor-context.tsx` to verify `clipboardObject` state and ensure `COPY_OBJECT` and `PASTE_OBJECT` actions are correctly implemented in the reducer.",
      "files_affected": [
        "client/src/lib/editor-context.tsx"
      ],
      "type": "MODIFY"
    },
    {
      "step": 2,
      "title": "Implement keyboard shortcut listener",
      "description": "Add a global `keydown` event listener in `client/src/components/editor/Canvas.tsx` (or a dedicated hook) to intercept Ctrl+C and Ctrl+V, triggering the respective dispatch actions.",
      "files_affected": [
        "client/src/components/editor/Canvas.tsx"
      ],
      "type": "MODIFY"
    },
    {
      "step": 3,
      "title": "Refine Paste Logic with Offset",
      "description": "Ensure the `PASTE_OBJECT` logic in the reducer or a helper function applies a visual offset (e.g., +20px X and Y) so duplicated objects don't perfectly overlap, and generates a new unique ID.",
      "files_affected": [
        "client/src/lib/editor-context.tsx"
      ],
      "type": "MODIFY"
    }
  ],
  "acceptance_criteria": [
    {
      "id": "c1",
      "description": "Pressing Ctrl+C when an object is selected updates the `clipboardObject` in `DocumentState`.",
      "how_to_verify": "Verify `editorReducer` handles `COPY_OBJECT` by setting `state.clipboardObject` to the object matching `uiState.selectedObjectId`."
    },
    {
      "id": "c2",
      "description": "Pressing Ctrl+V creates a new object in the `objects` array with a unique UUID.",
      "how_to_verify": "Verify `PASTE_OBJECT` action in `editorReducer` uses `uuidv4()` for the new object's ID."
    },
    {
      "id": "c3",
      "description": "Pasted objects are placed with a coordinate offset relative to the original.",
      "how_to_verify": "Check that `PASTE_OBJECT` logic increments `x` and `y` properties of the pasted object by a fixed value (e.g., 10 or 20)."
    },
    {
      "id": "c4",
      "description": "Keyboard listeners are cleaned up on component unmount.",
      "how_to_verify": "Check `useEffect` in `Canvas.tsx` for proper `removeEventListener` call."
    },
    {
      "id": "c5",
      "description": "Paste operation is blocked if the clipboard is empty or no layer is active.",
      "how_to_verify": "Verify conditional check in `PASTE_OBJECT` reducer case for `state.clipboardObject` existence."
    }
  ],
  "risks": [
    "Conflict with browser-native copy/paste if not using `e.preventDefault()` correctly for selected text.",
    "Race conditions between state updates if rapid-fire pasting occurs.",
    "Paste might fail if the original layer of the copied object was deleted."
  ]
}
